import { readFileSync, writeFileSync, readdirSync } from 'fs';
import { join } from 'path';

// Define the interfaces to ensure type safety
interface FileStats {
  fileType: string;
  count: number;
  totalLines: number;
  totalWords: number;
}

interface ProjectStatistics {
  timestamp: string;
  fileTypes: FileStats[];
  totals: {
    files: number;
    lines: number;
    words: number;
  };
}

function resortFileTypes(projectStats: ProjectStatistics): ProjectStatistics {
  projectStats.fileTypes.sort((a, b) => {
    // Primary sort by count (descending)
    if (b.count !== a.count) {
      return b.count - a.count;
    }
    // Secondary sort by totalLines (descending)
    if (b.totalLines !== a.totalLines) {
      return b.totalLines - a.totalLines;
    }
    // Tertiary sort by totalWords (descending)
    return b.totalWords - a.totalWords;
  });
  return projectStats;
}

function main() {
  const outputDir = join(process.cwd(), 'public', 'project-statistics', 'generated');
  console.log(`Scanning directory: ${outputDir}`);

  try {
    const allJsonFiles = readdirSync(outputDir)
      .filter(f => f.endsWith('.json') && f !== 'index.json');

    if (allJsonFiles.length === 0) {
      console.log('No statistics files found to resort.');
      return;
    }

    console.log(`Found ${allJsonFiles.length} files to process...`);

    for (const file of allJsonFiles) {
      const filePath = join(outputDir, file);
      try {
        const content = readFileSync(filePath, 'utf-8');
        let data: ProjectStatistics = JSON.parse(content);

        // Re-sort the fileTypes array
        data = resortFileTypes(data);

        // Write the updated data back to the file
        writeFileSync(filePath, JSON.stringify(data, null, 2), 'utf-8');
        console.log(`Successfully resorted and updated ${file}`);
      } catch (error) {
        console.error(`Error processing file ${file}:`, error);
      }
    }
    console.log('Finished processing all files.');
  } catch (error) {
    console.error(`Failed to read directory ${outputDir}:`, error);
  }
}

main();

