        const edgeColorForThisCell = edgePalette[state] || '#ffffff'; // Get color from palette
        edges.moveTo(x, y);
        edges.lineTo(x + scale, y);
        edges.lineTo(x + scale, y + scale);
        edges.lineTo(x, y + scale);
        edges.lineTo(x, y);
        edges.stroke({ color: colorToHex(edgeColorForThisCell), width: 1 });
        edgeContainer.addChild(edges);

        // Draw coordinates if enabled (add after cell so it's on top)
        if (showCoordinates) {
