  edgeColor: string,
  edgeWidth: number,
  visualizeEdgeDelta: boolean,
  showCoordinates: boolean
) {
  for (let row = 0; row < height; row++) {
    for (let col = 0; col < width; col++) {
      const x = col * scale;
      const y = row * scale;
