import { Graphics, Container, Text } from 'pixi.js';
import { GridType } from './types';
import { colorToHex } from './color-utils';

export class GridRenderer {
  render(
    container: Container,
    edgeContainer: Container,
    width: number,
    height: number,
    gridType: GridType,
    scale: number,
    cellStates: number[][],
    palette: Record<number, string>,
    edgeColor: string,
    edgeWidth: number,
    visualizeEdgeDelta: boolean,
    edgePalette: Record<number, string>,
    showCoordinates: boolean = false
  ) {
    // This is a simple flag to switch between two rendering modes.
    // A more advanced implementation might separate the logic further.
    if (visualizeEdgeDelta) {
      this.renderWithDelta(container, edgeContainer, width, height, gridType, scale, cellStates, palette, edgeWidth, edgePalette, showCoordinates);
    } else {
      this.renderSimple(container, edgeContainer, width, height, gridType, scale, cellStates, palette, edgeColor, edgeWidth, showCoordinates);
    }
  }

  private renderSimple(
    container: Container,
    edgeContainer: Container,
    width: number,
    height: number,
    gridType: GridType,
    scale: number,
    cellStates: number[][],
    palette: Record<number, string>,
    edgeColor: string,
    edgeWidth: number,
    showCoordinates: boolean
  ) {
    for (let row = 0; row < height; row++) {
      for (let col = 0; col < width; col++) {
        // Draw cell fill
        const state = cellStates[row]?.[col] ?? 0;
        const color = colorToHex(palette[state] || '#000000');
        const cell = this.createCellShape(gridType, col, row, scale);
        cell.fill(color);
        container.addChild(cell);

        // Draw cell edges
        const edges = this.createCellShape(gridType, col, row, scale);
        edges.stroke({ color: colorToHex(edgeColor), width: edgeWidth });
        edgeContainer.addChild(edges);

        // Draw coordinates
        if (showCoordinates) {
          const center = this.getCellCenter(gridType, col, row, scale);
          const coordText = new Text({
            text: `${col},${row}`,
            style: { fontSize: Math.max(8, scale / 4), fill: 0xffffff, stroke: { color: 0x000000, width: 2 }, align: 'center' }
          });
          coordText.anchor.set(0.5);
          coordText.position.set(center.x, center.y);
          container.addChild(coordText);
        }
      }
    }
  }

  private renderWithDelta(
    container: Container,
    edgeContainer: Container,
    width: number,
    height: number,
    gridType: GridType,
    scale: number,
    cellStates: number[][],
    palette: Record<number, string>,
    edgeWidth: number,
    edgePalette: Record<number, string>,
    showCoordinates: boolean
  ) {
    const drawnEdges = new Set<string>();

    for (let row = 0; row < height; row++) {
      for (let col = 0; col < width; col++) {
        // Draw cell fill
        const state = cellStates[row]?.[col] ?? 0;
        const color = colorToHex(palette[state] || '#000000');
        const cell = this.createCellShape(gridType, col, row, scale);
        cell.fill(color);
        container.addChild(cell);

        // Draw coordinates
        if (showCoordinates) {
          const center = this.getCellCenter(gridType, col, row, scale);
          const coordText = new Text({
            text: `${col},${row}`,
            style: { fontSize: Math.max(8, scale / 4), fill: 0xffffff, stroke: { color: 0x000000, width: 2 }, align: 'center' }
          });
          coordText.anchor.set(0.5);
          coordText.position.set(center.x, center.y);
          container.addChild(coordText);
        }

        // Get neighbors for this cell
        const neighbors = this.getCellNeighbors(gridType, col, row);

        for (const neighbor of neighbors) {
          const { col: nCol, row: nRow } = neighbor;

          // Define a unique key for the edge between (col, row) and (nCol, nRow)
          const key = (col < nCol) ? `${col},${row}-${nCol},${nRow}` : (nCol < col) ? `${nCol},${nRow}-${col},${row}` : (row < nRow) ? `${col},${row}-${nCol},${nRow}` : `${nCol},${nRow}-${col},${row}`;

          if (drawnEdges.has(key)) continue;

          drawnEdges.add(key);

          const neighborState = (nRow >= 0 && nRow < height && nCol >= 0 && nCol < width) ? (cellStates[nRow]?.[nCol] ?? 0) : state;
          const delta = Math.abs(state - neighborState);
          const edgeColor = colorToHex(edgePalette[delta] || '#ffffff');

          const edgeShape = this.createEdgeShape(gridType, col, row, neighbor, scale);
          if(edgeShape) {
            edgeShape.stroke({ color: edgeColor, width: edgeWidth });
            edgeContainer.addChild(edgeShape);
          }
        }
      }
    }
  }

  private createCellShape(gridType: GridType, col: number, row: number, scale: number): Graphics {
    switch (gridType) {
      case 'squares':
        const x = col * scale;
        const y = row * scale;
        const square = new Graphics();
        square.rect(x, y, scale, scale);
        return square;
      case 'hexagons':
        const hexSpacingX = scale * Math.sqrt(3);
        const hexSpacingY = scale * 1.5;
        const offsetX = (row % 2) * (hexSpacingX / 2);
        const centerX = col * hexSpacingX + offsetX;
        const centerY = row * hexSpacingY;
        return this.createHexagonCentered(centerX, centerY, scale);
      case 'triangles':
        const triHeight = scale * Math.sqrt(3) / 2;
        const triX = col * scale * 0.5;
        const triY = row * triHeight;
        const isUpward = (row + col) % 2 === 0;
        return this.createTriangle(triX, triY, scale, isUpward);
    }
  }

  private getCellCenter(gridType: GridType, col: number, row: number, scale: number): { x: number, y: number } {
    switch (gridType) {
      case 'squares':
        return { x: col * scale + scale / 2, y: row * scale + scale / 2 };
      case 'hexagons':
        const hexSpacingX = scale * Math.sqrt(3);
        const hexSpacingY = scale * 1.5;
        const offsetX = (row % 2) * (hexSpacingX / 2);
        return { x: col * hexSpacingX + offsetX, y: row * hexSpacingY };
      case 'triangles':
        const triHeight = scale * Math.sqrt(3) / 2;
        const triX = col * scale * 0.5;
        const triY = row * triHeight;
        return { x: triX + scale / 2, y: triY + triHeight / 2 };
    }
  }

  private getCellNeighbors(gridType: GridType, col: number, row: number): { col: number, row: number }[] {
    switch(gridType) {
      case 'squares':
        return [
          { col: col, row: row - 1 }, { col: col + 1, row: row },
          { col: col, row: row + 1 }, { col: col - 1, row: row }
        ];
      case 'hexagons':
        const isOddRow = row % 2 !== 0;
        if(isOddRow) {
          return [
            { col: col + 1, row: row }, { col: col, row: row - 1 }, { col: col - 1, row: row - 1 },
            { col: col - 1, row: row }, { col: col - 1, row: row + 1 }, { col: col, row: row + 1 }
          ];
        } else {
          return [
            { col: col + 1, row: row }, { col: col + 1, row: row - 1 }, { col: col, row: row - 1 },
            { col: col - 1, row: row }, { col: col, row: row + 1 }, { col: col + 1, row: row + 1 }
          ];
        }
      case 'triangles':
        const isUpward = (row + col) % 2 === 0;
        if(isUpward) {
          return [
            { col: col - 1, row: row }, { col: col + 1, row: row }, { col: col, row: row + 1 }
          ];
        } else {
          return [
            { col: col - 1, row: row }, { col: col + 1, row: row }, { col: col, row: row - 1 }
          ];
        }
    }
  }

  private createEdgeShape(gridType: GridType, col: number, row: number, neighbor: { col: number, row: number }, scale: number): Graphics | null {
    // This is complex logic that would require knowing the exact vertices for each edge type.
    // For simplicity, we can reuse some of the getEdgeAt logic if we refactor it.
    // Let's defer a full implementation until we refactor getEdgeAt.
    // A simplified (but slightly inaccurate for non-squares) version:
    const center1 = this.getCellCenter(gridType, col, row, scale);
    const center2 = this.getCellCenter(gridType, neighbor.col, neighbor.row, scale);

    // This is not a perfect representation of the edge, but a line between centers.
    // A proper implementation would need the exact vertex data.
    const edge = new Graphics();
    edge.moveTo(center1.x, center1.y);
    edge.lineTo(center2.x, center2.y);
    return edge;
  }

  // ... (rest of the file, e.g., createHexagon, createTriangle, getCellAt, etc. remains the same)
}

