        this.renderSquares(container, edgeContainer, width, height, scale, cellStates, palette, edgeColor, edgeWidth, showCoordinates);
        break;
      case 'hexagons':
        this.renderHexagons(container, edgeContainer, width, height, scale, cellStates, palette, edgeColor, edgeWidth, showCoordinates);
        break;
      case 'triangles':
        this.renderTriangles(container, edgeContainer, width, height, scale, cellStates, palette, edgeColor, edgeWidth, showCoordinates);
        break;
    }
  }

  private renderSquares(
    container: Container,
    edgeContainer: Container,
    width: number,
    height: number,
    scale: number,
    cellStates: number[][],
    palette: Record<number, string>,
    edgeColor: string,
    edgeWidth: number,
    showCoordinates: boolean
  ) {
    for (let row = 0; row < height; row++) {
      for (let col = 0; col < width; col++) {
        const x = col * scale;
        const y = row * scale;
        const state = cellStates[row]?.[col] ?? 0;
        const color = colorToHex(palette[state] || '#000000');

        // Draw cell
        const cell = new Graphics();
        cell.rect(x, y, scale, scale);
        cell.fill(color);
        container.addChild(cell);

        // Draw edges
        const edges = new Graphics();
        edges.moveTo(x, y);
        edges.lineTo(x + scale, y);
        edges.lineTo(x + scale, y + scale);
        edges.lineTo(x, y + scale);
        edges.lineTo(x, y);
        edges.stroke({ color: colorToHex(edgeColor), width: edgeWidth });
        edgeContainer.addChild(edges);

        // Draw coordinates if enabled (add after cell so it's on top)
        if (showCoordinates) {
          const coordText = new Text({
            text: `${col},${row}`,
            style: {
              fontSize: Math.max(8, scale / 4),
              fill: 0xffffff,
              stroke: { color: 0x000000, width: 2 },
              align: 'center',
            },
          });
          coordText.anchor.set(0.5);
          coordText.x = x + scale / 2;
          coordText.y = y + scale / 2;
          container.addChild(coordText);
        }
